SELECT *
FROM ts_role_info
WHERE user_id = #{query.userId}

    AND (
        role_name LIKE CONCAT('%', #{query.keyword}, '%')
        OR role_subtitle LIKE CONCAT('%', #{query.keyword}, '%')
        OR intro_text LIKE CONCAT('%', #{query.keyword}, '%')
    )


    AND gender = #{query.gender}


    AND is_public = #{query.isPublic}



        AND status = #{query.status}


        AND (status IS NULL OR status != 0)


ORDER BY updated_at DESC, id DESC

SELECT *
FROM ts_role_info
WHERE id = #{id}
  AND user_id = #{userId}
  AND (status IS NULL OR status != 0)
LIMIT 1

SELECT id
FROM ts_role_info
WHERE user_id = #{userId}
  AND (status IS NULL OR status != 0)
  AND id IN

    #{roleId}
